```typescript
// Define a shape (Interface)
interface Bird {
  fly(): void;
  layEgg(): void;
}

// This function expects a 'Bird'
function letItFly(bird: Bird) {
  bird.fly();
}

// This class is NOT named 'Bird', and does not 'extend' anything.
class Plane {
  fly() { console.log("Flying!"); }
  layEgg() { console.log("Dropping payload!"); } // Matches the shape
}

// TypeScript accepts this because Plane has the same 'shape' as Bird
// This is TypeScript doing "Duck Typing" at compile time.
letItFly(new Plane()); 
```

